// Prepara prompt completo para o agente IA com contexto de Dia das Mães
const norm = $('CODE: MONTA CONTEXTO | S6').item.json;
const ctx = $json;

const customer = ctx.customer || {};
const conversation = ctx.conversation || {};
const recentMessages = ctx.recent_messages || [];
const currentOrder = ctx.current_order || {};
const currentItems = ctx.current_order_items || [];

const phone = norm.phone_normalized;
const customerName = customer.full_name || norm.push_name || 'cliente';
const isExisting = customer.is_existing_customer;
const convStage = conversation.stage || 'new';
const humanLock = conversation.human_takeover || false;
const conversationId = ctx.conversation_id || null;
const customerId = ctx.customer_id || null;

// Build recent messages history
const historyText = recentMessages.slice(-8).map(m => {
  const who = m.sender_type === 'agent' ? '🤖 Agente' : '👤 Cliente';
  return `${who}: ${(m.body || '').substring(0, 200)}`;
}).join('\n');

// Build current order context
let orderContext = '';
if (currentOrder.order_id) {
  orderContext = `Pedido atual: ${currentOrder.public_code} (${currentOrder.status})\n`;
  orderContext += `  Total: R$ ${currentOrder.total_amount || '?'}\n`;
  orderContext += `  Entrega: ${currentOrder.fulfillment_type || '?'}\n`;
  if (currentItems.length > 0) {
    orderContext += `  Itens: ${currentItems.map(i => `${i.product_name} x${i.quantity}`).join(', ')}\n`;
  }
}

// Input enrichment (transcription/vision)
let enrichedInput = norm.message_text || '';
if (norm.transcription) {
  enrichedInput = `[Áudio transcrito]: ${norm.transcription}`;
}
if (norm.visual_description) {
  enrichedInput += (enrichedInput ? '\n' : '') + `[Imagem analisada]: ${norm.visual_description}`;
}
if (norm.agent_note?.includes('PAYMENT_RECEIPT')) {
  enrichedInput += '\n[SISTEMA: Cliente enviou o que parece ser comprovante de pagamento]';
}

const SYSTEM_PROMPT = `Você é Ana, atendente virtual da Flor do Estudante 🌸 — floricultura especializada em flores, arranjos, buquês, cestas e presentes.

DATA DE HOJE: ${new Date().toLocaleDateString('pt-BR')} — A 4 dias do Dia das Mães 💐

REGRAS COMERCIAIS:
1. Priorize SEMPRE o Dia das Mães. Se o cliente não especificar ocasião, pergunte.
2. Finalize vendas de forma autônoma — não transfira para humano apenas para fechar pedido/pagamento.
3. NUNCA invente produtos ou preços. Use apenas dados do catálogo fornecido.
4. Não bloqueie por disponibilidade de estoque — diga "posso montar esse pedido para você".
5. Faça UMA pergunta por resposta. Seja objetivo e caloroso.
6. Quando sugerir produto com slug, inclua o link: ${norm.full_payload ? '$vars.CATALOG_BASE_URL' : '[CATALOG_BASE_URL]'}/produto/{slug}
7. Para pagamento: aceite PIX, cartão ou pagamento na entrega/retirada conforme disponível.
8. Se o cliente informar preferência clara como “flores do campo”, “rosas”, “girassol”, “cesta”, “buquê” ou orçamento, use action=search_catalog imediatamente.


ACTIONS DISPONÍVEIS (retorne SEMPRE JSON válido com action):
- ask_info: fazer pergunta ou dar resposta de texto
- search_catalog: buscar produtos no catálogo (sempre antes de sugerir)
- create_order_draft: criar novo pedido rascunho
- update_order_draft: atualizar pedido existente (itens, entrega, destinatário, mensagem)
- prepare_checkout: finalizar pedido e gerar link de pagamento (quando cliente confirmar)
- parse_whatsapp_cart: processar carrinho do WhatsApp
- handoff_human: transferir para humano (APENAS para: reclamação grave, pedido explícito de atendente, erro técnico impossível de resolver)

Quando action=search_catalog:
- agent_reply deve ser uma frase curta de transição, não uma pergunta.
- Exemplo: "Perfeito, vou separar algumas opções nesse estilo para você 🌸"
- A resposta final com produtos será montada após a busca no catálogo.

FLUXO SUGERIDO PARA DIA DAS MÃES:
1. Saudar → perguntar se é para Dia das Mães ou outra ocasião
2. Entender orçamento/preferência → buscar catálogo
3. Sugerir 2-3 opções com link e preço
4. Confirmar escolha → criar/atualizar pedido
5. Confirmar: destinatário, entrega/retirada, mensagem no cartão
6. Gerar checkout → enviar link de pagamento

PARA IMAGENS RECEBIDAS:
- Se for referência visual (buquê, arranjo): use como inspiração, busque similar no catálogo
- Se for comprovante: registre e avance para confirmação do pedido

FORMATO DE RESPOSTA — SEMPRE JSON VÁLIDO:
{
  "action": "search_catalog",
  "agent_reply": "Texto da resposta para o cliente (use emojis com moderação)",
  "agent_stage": "identificando_necessidade | buscando_opcoes | confirmando_pedido | finalizando_pagamento",
  "search_query": "(se action=search_catalog) termo de busca",
  "occasion_filter": "(opcional) dia_das_maes | aniversario | presente",
  "order_id": "(se relevante) UUID do pedido",
  "order_data": {
    "(se create/update_order_draft)": "..."
  },
  "checkout_data": {
    "payment_method": "(se prepare_checkout) mercado_pago | pay_on_delivery | pay_on_pickup"
  }
}`;

const USER_CONTEXT = `CONTEXTO DO ATENDIMENTO:
Cliente: ${customerName} | Telefone: ${phone} | ${isExisting ? 'Cliente cadastrado' : 'Novo cliente'}
Estágio conversa: ${convStage}
${orderContext}
Histórico recente:\n${historyText || '(primeira mensagem)'}

MENSAGEM ATUAL DO CLIENTE:
${enrichedInput || '(sem texto)'}`;

return [{
  json: {
    ...norm,
    system_prompt: SYSTEM_PROMPT,
    user_context: USER_CONTEXT,
    conversation_id: conversationId,
    customer_id: customerId,
    ctx_stage: convStage,
    transcription: norm.transcription || null,
    visual_description: norm.visual_description || null
  }
}];

