// @ts-nocheck
// Parse e valida resposta JSON do agente
const norm = $('CODE: PREPARA PROMPT | S6').item.json;
const llmResp = $json;

const VALID_ACTIONS = [
  'ask_info', 'search_catalog', 'create_order_draft', 'update_order_draft',
  'prepare_checkout', 'parse_whatsapp_cart', 'handoff_human'
];

const VALID_STAGES = [
  'new',
  'smalltalk',
  'identificando_necessidade',
  'coletando_ocasiao',
  'coletando_preferencia',
  'coletando_orcamento',
  'consultando_catalogo',
  'buscando_opcoes',
  'apresentando_opcoes',
  'pedido_em_montagem',
  'confirmando_pedido',
  'coletando_entrega_ou_retirada',
  'coletando_destinatario',
  'coletando_mensagem_cartao',
  'finalizando_pagamento',
  'aguardando_pagamento',
  'aguardando_confirmacao_humana',
  'handoff',
  'human_takeover',
  'finalizado',
  'erro'
];

let parsed = null;
let rawContent = '';

try {
  rawContent = llmResp.choices?.[0]?.message?.content || '{}';
  // Try direct parse
  try { parsed = JSON.parse(rawContent); } catch (_) {}
  // Try extracting JSON from markdown block
  if (!parsed) {
    const m = rawContent.match(/```(?:json)?\s*([\s\S]+?)```/);
    if (m) { try { parsed = JSON.parse(m[1]); } catch (_) {} }
  }
  // Try extracting first {...}
  if (!parsed) {
    const m2 = rawContent.match(/\{[\s\S]+\}/);
    if (m2) { try { parsed = JSON.parse(m2[0]); } catch (_) {} }
  }
} catch (e) {
  parsed = null;
}

// Fallback if parsing failed
if (!parsed || typeof parsed !== 'object') {
  return [{ json: {
    ...norm,
    agent_action: 'ask_info',
    agent_reply: 'Desculpe, tive um pequeno problema. Pode repetir sua mensagem? 🌸',
    agent_stage: norm.ctx_stage || 'identificando_necessidade',
    parse_error: true,
    raw_content: rawContent.substring(0, 500)
  }}];
}

// Validate and sanitize
const action = VALID_ACTIONS.includes(parsed.action) ? parsed.action : 'ask_info';
const stage = VALID_STAGES.includes(parsed.agent_stage) ? parsed.agent_stage : (norm.ctx_stage || 'identificando_necessidade');
const reply = (parsed.agent_reply || '').toString().trim();

if (!reply && action === 'ask_info') {
  return [{ json: {
    ...norm,
