if (Array.isArray(catalogResp)) products = catalogResp;
else if (Array.isArray(catalogResp.items)) products = catalogResp.items;
else if (Array.isArray(catalogResp.products)) products = catalogResp.products;

if (products.length === 0) {
  return [{ json: {
