let replyText = agentCtx.agent_reply || 'Veja as opções que encontrei:\n';
const imageProducts = products.filter(p => p.cover_image_url);

if (!replyText.includes('R$') && products.length > 0) {
  const lines = products.slice(0, 3).map((p, i) => {
    const url = `${catalogBase}/produto/${p.slug || ''}`;
    const price = p.price ? `R$ ${parseFloat(p.price).toFixed(2).replace('.', ',')}` : '';
    const label = i === 0 ? '🌸' : i === 1 ? '💐' : '🌺';
    return `${label} *${p.name}*${price ? ' — ' + price : ''}\n${p.short_description || ''}\n${url}`;
  });
  replyText = (agentCtx.agent_reply || 'Encontrei estas opções para você:') + '\n\n' + lines.join('\n\n');
}

return [{ json: {
  ...agentCtx,
  agent_reply: replyText,
  catalog_results: products,
  has_catalog_images: imageProducts.length > 0,
  first_image_product: imageProducts[0] || null,
